kwh = int(input())

if kwh <= 200:
    bill = kwh * 100
elif kwh <= 400:
    # 200kWh까지는 100원, 나머지(200 초과분)는 200원
    bill = 200 * 100 + (kwh - 200) * 200
else:
    # 200kWh는 100원, 다음 200kWh는 200원, 나머지(400 초과분)는 300원
    bill = 200 * 100 + 200 * 200 + (kwh - 400) * 300

print(bill)

